const html = $json.data;
const baseUrl = 'https://n8n.srv1257557.hstgr.cloud/webhook';

const email = $json.email || 
              ($node["Get row(s) in sheet"] ? $node["Get row(s) in sheet"].json["Subscriber email"] : "") || 
              ($node["Settings"] ? $node["Settings"].json.testEmail : "");

let finalHtml = html;

// 1. HERO IMAGE TRACKING
const openUrl = `${baseUrl}/open-tracking?email=${encodeURIComponent(email)}`;
const headerImageUrl = "https://raw.githubusercontent.com/jcsavoy/JC-Savoy-Newsletter/main/header-april-2026.png";
if (finalHtml.includes(headerImageUrl)) {
  finalHtml = finalHtml.split(headerImageUrl).join(openUrl);
}

// 2. GAZETTE & JOKE BUTTONS (Anchor replacement)
const feedbackTracking = [
  { anchor: '#gazette-up', section: 'Gazette', vote: 'up' },
  { anchor: '#gazette-down', section: 'Gazette', vote: 'down' },
  { anchor: '#joke-up', section: 'Joke', vote: 'up' },
  { anchor: '#joke-down', section: 'Joke', vote: 'down' }
];

feedbackTracking.forEach(f => {
  const url = `${baseUrl}/feedback-tracking?email=${encodeURIComponent(email)}&section=${f.section}&vote=${f.vote}`;
  finalHtml = finalHtml.split(f.anchor).join(url);
});

// 3. RECIPE BUTTONS (Anchor replacement)
const recipeOptions = [
  { anchor: '#recipe-going', vote: 'going' },
  { anchor: '#recipe-liked', vote: 'liked' },
  { anchor: '#recipe-disliked', vote: 'disliked' }
];

recipeOptions.forEach(r => {
  const url = `${baseUrl}/feedback-tracking?email=${encodeURIComponent(email)}&section=Recipe&vote=${r.vote}`;
  finalHtml = finalHtml.split(r.anchor).join(url);
});

// 4. CLICK TRACKING
const clickUrl = `${baseUrl}/click-tracking?email=${encodeURIComponent(email)}`;
finalHtml = finalHtml.replace(/<a\s+(?:[^>]*?\s+)?href="([^#][^"]*)"/gi, (match, url) => {
  if (url.startsWith('http') && !url.includes('unsubscribe') && !url.includes('tracking')) {
    return match.replace(url, `${clickUrl}&url=${encodeURIComponent(url)}`);
  }
  return match;
});

// 5. Update Unsubscribe Link
const unsubUrl = `${baseUrl}/unsubscribe?email=${encodeURIComponent(email)}`;
finalHtml = finalHtml.replace(/##UNSUBSCRIBE_LINK##/g, unsubUrl);

return { finalHtml, email };
